#include <iostream>

// The function to be tested
int incrementPointerValue(int* ptr) {
    *ptr += 5;
    return *ptr;
}

int main() {
    std::cout << "Running test cases for Robustness Issue...\n";

    // Test Case 1: Valid pointer
    int value1 = 10;
    std::cout << "Original value: " << value1 << std::endl;
    int result1 = incrementPointerValue(&value1);
    std::cout << "Value after increment (valid ptr): " << value1 << std::endl;
    std::cout << "Returned new value (valid ptr): " << result1 << std::endl;

    std::cout << "\nTest Case 2: Null pointer (EXPECTED CRASH)\n";
    int* nullPtr = nullptr;
    // This call is expected to cause a segmentation fault
    int result2 = incrementPointerValue(nullPtr); 
    std::cout << "If you see this line, the program did not crash as expected for nullptr. Result: " << result2 << std::endl;

    return 0;
}
